#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI N = 4e5 + 5;
int f[N];
vector<int> g[N];
PII t[N];
int vis[N], bad[N], ans[N], n, m, q;
int find(int x)
{
	if (f[x] != x) f[x] = find(f[x]);
	return f[x];
}
void merge(int x, int y)
{
	int fx = find(x), fy = find(y);
	f[fy] = fx;
}

int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin >> n >> m;
	for (int i = 0; i < n; i++) f[i] = i;
	for (int i = 1; i <= m; i++)
	{
		int x, y;
		cin >> x >> y;
		g[x].push_back(y);
		g[y].push_back(x);
		t[i] = {x, y};
	}
	cin >> q;
	for (int i = 1; i <= q; i++)
	{
		cin >> bad[i];
		vis[bad[i]] = 1;
	}
	ans[q + 1] = n - q;
	for (int i = 1; i <= m; i++)
	{
		int x = t[i].first, y = t[i].second;
		if (!vis[x] && !vis[y] && find(x) != find(y))
		{
			merge(x, y);
			ans[q + 1]--;
		}
	}

	for (int i = q; i >= 1; i--)
	{
		int x = bad[i];
		vis[x] = 0;
		ans[i] = ans[i + 1] + 1;
		for (int y : g[x])
		{
			if (!vis[y] && find(x) != find(y))
			{
				merge(x, y);
				ans[i]--;
			}
		}
	}
	for (int i = 1; i <= q + 1; i++)
		cout << ans[i] << '\n';
	return false;
}
